import numpy as np

def iterative_repair_schedule(processing_times: list[int], deadlines: list[int], initial_order: list[int], max_iter: int = 100) -> tuple[list[int], int]:
    pt = np.array(processing_times, dtype=np.int64)
    dl = np.array(deadlines, dtype=np.int64)
    order = np.array(initial_order, dtype=np.int64)
    n = len(order)

    def compute_tardiness(ord_arr):
        completion = np.cumsum(pt[ord_arr])
        return int(np.sum(np.maximum(0, completion - dl[ord_arr])))

    for _ in range(max_iter):
        current = compute_tardiness(order)
        best_gain = 0
        best_i = -1

        for i in range(n - 1):
            order[i], order[i + 1] = order[i + 1], order[i]
            new_tard = compute_tardiness(order)
            gain = current - new_tard
            if gain > best_gain:
                best_gain = gain
                best_i = i
            order[i], order[i + 1] = order[i + 1], order[i]

        if best_i == -1:
            break
        order[best_i], order[best_i + 1] = order[best_i + 1], order[best_i]

    return order.tolist(), compute_tardiness(order)
